// Script Continued Below
gs.info("Tasker - Fix Script - Executing 'Sync of Org Hierarchy with Org Unit Tables'");
var orgHierarchyTableName = "x_153465_discovert_discover_office_hierarchy";
var orgMemberTableName = "x_153465_discovert_discover_office_members";
var orgUserTableName = "x_153465_discovert_organization_user";
var fixScriptName = "Fix Script - Sync OUHA, TM, TA per OU";
//function to get a GlideRecord query results matching the members with the given role for an org structure
function setUsersInGlobalRole(role, orgTableField, arrUsersInGlobalRole) {
	try{
		arrUsersInGlobalRole.forEach(function(user_sys_id){
			var userId = user_sys_id.toString();
			var grOrgUser = new GlideRecord(orgUserTableName);
			grOrgUser.addQuery("u_tasker_user.sys_id", userId);
			grOrgUser.query();
			var userFound = false;
			while(grOrgUser.next()) {
				userFound=true;
				if(role != "x_153465_discovert.tasker_user"){
					grOrgUser.setValue(orgTableField,true);
				}
			}
			if(!userFound){
				var userDisplayName = "";
				var grUser = new GlideRecord("sys_user");
				if(grUser.get(userId)){
					userDisplayName = grUser.getDisplayValue();
				}
				gs.error("User: " + userDisplayName + " with GUID: " + userId + " has role: " + role + " but is not in any Tasker Organizaitonal Units");
			}
		});
	} catch(ex){
		gs.error(fixScriptName + " - error in setUsersInGlobalRole - error: " + JSON.stringify(ex) + " parameters[role: " + role + " - orgTableField: " + orgTableField + " - arrUsersInGlobalRole: " + arrUsersInGlobalRole + "]");
	}		
}

function removeUsersFromGlobalRoles(orgTableField, arrUsersInGlobalRole){
	try{
		var grOrgUser = new GlideRecord(orgUserTableName);
		grOrgUser.addQuery(orgTableField, 'true');
		grOrgUser.query();
		while(grOrgUser.next()) {
			roleSetForUser = arrUsersInGlobalRole.filter(function(user_sys_id){
				var userId = user_sys_id.toString();
				return userId == grOrgUser.getValue("u_tasker_user") + "";
			});
			if(roleSetForUser.length<1){
				grOrgUser.setValue(orgTableField,false);
			}
		}
	} catch(ex){
		gs.error(fixScriptName + " - error in removeUsersFromGlobalRoles - error: " + JSON.stringify(ex) + " parameters[orgTableField: " + orgTableField + " - arrUsersInGlobalRole: " + arrUsersInGlobalRole + "]");
	}
}

try{
	//function to get a GlideRecord query results matching the members with the given role for an OU
	var getOURoleRecords = function(role, ouSysId) {
		var grOUroleRecords = new GlideRecord(orgMemberTableName);
		try{

			grOUroleRecords.addQuery("discover_office_hierarchy", ouSysId);
			grOUroleRecords.addQuery(role, "true");
			grOUroleRecords.query();
			return grOUroleRecords;
		} catch(ex){
			gs.error(fixScriptName + " - error in setUsersInGlobalRole - error: " + JSON.stringify(ex) + " parameters[role: " + role + " - ouSysId: " + ouSysId + "]");
			return grOUroleRecords;
		}
	};

	//function to get a GlideRecord query results matching the members with the given role for an org structure
	var getUsersInGlobalRole = function(role) {
		var arrUsersInGlobalRole = [];
		try{
			var grUserRoles = new GlideRecord('sys_user_has_role');
			grUserRoles.addQuery('role.name', role);
			grUserRoles.query();
			while(grUserRoles.next()) {
				arrUsersInGlobalRole.push(grUserRoles.getValue('user')); 
			}
			var au = new global.ArrayUtil();
			arrUsersInGlobalRole = au.unique(arrUsersInGlobalRole);
			return arrUsersInGlobalRole;
		} catch(ex){
			gs.error(fixScriptName + " - error in getUsersInGlobalRole  - error: " + JSON.stringify(ex) + " parameters[role: " + role + "]");
			return arrUsersInGlobalRole;
		}

	};

	var getAdminstratorsForOrgStructure = function(arrUsersInGlobalRole, top_ou){
		var arrOrgStructureTA = [];
		var orgStructureTAList = "";
		try{
			arrUsersInGlobalRole.forEach(function(member){
				var strMember = member.toString();
				var usersInOU = new GlideRecord(orgMemberTableName);
				usersInOU.addQuery("discover_office_hierarchy.u_top_ou", top_ou);
				usersInOU.addQuery("office_member",strMember);
				if(usersInOU.next()){
					arrOrgStructureTA.push(strMember);
				}
			});
			orgStructureTAList = arrOrgStructureTA.join(",");
			return orgStructureTAList;
		} catch(ex){
			gs.error(fixScriptName + " - error in getAdminstratorsForOrgStructure - error: " + JSON.stringify(ex) + " parameters[top_ou: " + top_ou + " - arrUsersInGlobalRole: " + arrUsersInGlobalRole + "]");
			return orgStructureTAList;
		}

	};

	//for each record in hierarchy table
	//get hierarchy table
	var hierarchyTable = new GlideRecord(orgHierarchyTableName);
	hierarchyTable.query();
	while(hierarchyTable.next()) {
		try {
			// get ou sysid
			var ouId = hierarchyTable.getUniqueValue();
			var ouDisplayName = hierarchyTable.getDisplayValue();
			gs.info(fixScriptName + " - Checking OU: ====" + ouDisplayName + "====");
			// find all members in ou with Task Manager role
			var ouTMRecords = getOURoleRecords('office_task_authority', ouId);
			var taskManagerList = "";
			while(ouTMRecords.next()) {
				try {
					//add user ref of any record containing true for 
					//"office_task_authority" to hierarchy table list "tasking_authorities"		
					var taskManagerId = ouTMRecords.getValue("office_member");
					taskManagerList  = (taskManagerList) ? taskManagerList + "," + taskManagerId : taskManagerId;
				} catch(ex) {
					gs.error(fixScriptName + " - error in getting Task Manager list for OU - error: " + JSON.stringify(ex) + " parameters[OU: " + ouDisplayName + " - taskManagerId: " + taskManagerId + "]");
				}					
			}

			// find all members in ou with Task Manager role
			var ouHARecords = getOURoleRecords('is_office_administrator', ouId);
			var ouHAList = "";
			while(ouHARecords.next()) {
				try {
					//add user ref of any record containing true for 
					//"office_task_authority" to hierarchy table list "tasking_authorities"		
					var ouHAId = ouHARecords.getValue("office_member");
					ouHAList  = (ouHAList) ? ouHAList + "," + ouHAId : ouHAId;
				} catch(ex) {
					gs.error(fixScriptName + " - error in getting OUHA list for OU - error: " + JSON.stringify(ex) + " parameters[OU: " + ouDisplayName + " - ouHAId: " + ouHAId + "]");
				}

			}

			hierarchyTable.setValue("tasking_authorities", taskManagerList);
			gs.info(fixScriptName + " - OU: " + ouDisplayName + " - Task Managers: " + taskManagerList);

			hierarchyTable.setValue("u_ou_hierarchy_administrators", ouHAList);
			gs.info(fixScriptName + " - OU: " + ouDisplayName + " - OU Hierarchy Administrators: " + ouHAList);
			hierarchyTable.update();
		} catch(ex){
			gs.error(fixScriptName + " - error in Hierachy Role Update loop  - error: " + JSON.stringify(ex) + " parameters[ouDisplayName: " + ouDisplayName + "]");
		}

	}

	var arrAllTAAs = getUsersInGlobalRole("x_153465_discovert.tasker_application_admin");
	gs.info(fixScriptName + " - the following user_ids have the Tasker Application Admin Role: " + JSON.stringify(arrAllTAAs));
	setUsersInGlobalRole("x_153465_discovert.tasker_application_admin", "is_tasker_application_administrator", arrAllTAAs);
	removeUsersFromGlobalRoles("is_tasker_application_administrator", arrAllTAAs);

	var arrAllGHA = getUsersInGlobalRole("x_153465_discovert.tasker_organizational_admin");
	gs.info(fixScriptName + " - the following user_ids have the Global Hierarcy Administrator Role: " + JSON.stringify(arrAllGHA));
	setUsersInGlobalRole("x_153465_discovert.tasker_organizational_admin", "is_global_hierarchy_administrator", arrAllGHA);
	removeUsersFromGlobalRoles("is_global_hierarchy_administrator", arrAllGHA);

	var arrAllTemplateAdmins = getUsersInGlobalRole("x_153465_discovert.tasker_process_template_admin");
	gs.info(fixScriptName + " - the following user_ids have the Template Permisssions Administrator Role: " + JSON.stringify(arrAllTemplateAdmins));
	setUsersInGlobalRole("x_153465_discovert.tasker_process_template_admin", "can_manage_template_permissions", arrAllTemplateAdmins);
	removeUsersFromGlobalRoles("can_manage_template_permissions", arrAllTemplateAdmins);

	var arrAllGTDs = getUsersInGlobalRole("x_153465_discovert.tasker_process_template_global");
	gs.info(fixScriptName + " - the following user_ids have the Global Template Designer Role: " + JSON.stringify(arrAllGTDs));
	setUsersInGlobalRole("x_153465_discovert.tasker_process_template_global", "can_manage_global_template", arrAllGTDs);
	removeUsersFromGlobalRoles("can_manage_global_template", arrAllGTDs);

	var arrAllTaskerUsers = getUsersInGlobalRole("x_153465_discovert.tasker_user");
	gs.info(fixScriptName + " - the following user_ids have the Tasker User Role: " + JSON.stringify(arrAllTaskerUsers));
	setUsersInGlobalRole("x_153465_discovert.tasker_user", "TaskerUserRole", arrAllTaskerUsers);
	removeUsersFromGlobalRoles("TaskerUserRole", arrAllTaskerUsers);

	var arrAllTEs = getUsersInGlobalRole("x_153465_discovert.Task_Executive");
	gs.info(fixScriptName + " - the following user_ids have the Task Exectutive Role: " + JSON.stringify(arrAllTEs));
	setUsersInGlobalRole("x_153465_discovert.Task_Executive", "is_task_executive", arrAllTEs);
	removeUsersFromGlobalRoles("is_task_executive", arrAllTEs);

	var arrAllTaskAdministrators = getUsersInGlobalRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
	gs.info(fixScriptName + " - the following user_ids have the Task Administrator Role: " + JSON.stringify(arrAllTaskAdministrators));
	setUsersInGlobalRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin", "is_task_administrator", arrAllTaskAdministrators);
	removeUsersFromGlobalRoles("is_task_administrator", arrAllTaskAdministrators);

	//for each top ou record in hierarchy table
	var grTopOURecords = new GlideRecord(orgHierarchyTableName);
	grTopOURecords.addNullQuery('parent').addOrCondition('parent', '');
	grTopOURecords.query();
	while(grTopOURecords.next()) {
		try {
			var topOUDisplayName = grTopOURecords.getDisplayValue();
			// get topOU sysid
			var topOU = grTopOURecords.getUniqueValue();
			var taskAdministratorList = getAdminstratorsForOrgStructure(arrAllTaskAdministrators, topOU);
			gs.info(fixScriptName + " - collected Task Administrator Users: " + taskAdministratorList + " for Organizational Structure with Tob OU: " + topOUDisplayName);
			// if anything changed, call the update (max once per record)
			gs.info(fixScriptName + " - Setting Task Administrators for organizational structure with top OU: " + topOUDisplayName);
			grTopOURecords.setValue("u_global_authorities", taskAdministratorList);
			grTopOURecords.update();
		} catch(ex){
			gs.error(fixScriptName + " - error in Top OU Administrator update loop  - error: " + JSON.stringify(ex) + " parameters[topOUDisplayName: " + topOUDisplayName + "]");
		}
	}
	gs.info(fixScriptName + " - COMPLETE");
} catch(ex){
	gs.error(fixScriptName + " - uncaught error in Fix Script main  - error: " + JSON.stringify(ex));
}
